import sys
it = iter(sys.stdin.read().split())
R, C = int(next(it)), int(next(it))
maze = [[int(next(it)) for _ in range(C)] for _ in range(R)]
def solve_maze(R, C, maze):
    directions = [(0, 1), (0, -1), (1, 0), (-1, 0)]
    queue = [(0, 0, [(0, 0)])]
    visited = {(0, 0)}
    while queue:
        x, y, path = queue.pop(0)
        if x == R - 1 and y == C - 1:
            return 'PATH ' + ' '.join(f'({x},{y})' for x, y in path)
        for dx, dy in directions:
            nx, ny = x + dx, y + dy
            if 0 <= nx < R and 0 <= ny < C and maze[nx][ny] == 0 and (nx, ny) not in visited:
                queue.append((nx, ny, path + [(nx, ny)]))
                visited.add((nx, ny))
    return 'NO PATH'
print(solve_maze(R, C, maze))

